mapper.select:
select id, user_id, game_type, level_num, updated_at
from user_progress
where user_id = #{userId}
  and game_type = #{gameType, jdbcType=INTEGER, typeHandler=com.sniper.game.wordgame.typehandler.GameTypeEnumTypeHandler}
limit 1

mapper.update:
update user_progress
set level_num = #{levelNum},
    updated_at = now()
where user_id = #{userId}
  and game_type = #{gameType, jdbcType=INTEGER, typeHandler=com.sniper.game.wordgame.typehandler.GameTypeEnumTypeHandler}
